/* Default: items fill rows left-to-right */
.row-flow {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  grid-auto-rows: 100px;
  grid-auto-flow: row;
  gap: 12px;
}
/* Items: 1 2 3
         4 5 6
         7 8 9 */

/* Column flow: items fill columns top-to-bottom */
.column-flow {
  display: grid;
  grid-template-rows: repeat(3, 100px);
  grid-auto-columns: 1fr;
  grid-auto-flow: column;
  gap: 12px;
}
/* Items: 1 4 7
         2 5 8
         3 6 9 */

.gallery {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  grid-auto-rows: 150px;
  grid-auto-flow: dense;
  gap: 12px;
}

/* Some items span 2 columns */
.gallery-item-wide {
  grid-column: span 2;
}

/* Some items span 2 rows */
.gallery-item-tall {
  grid-row: span 2;
}

/* Without dense: gaps appear when wide items don't fit
   [1] [wide-2 ] [  ] [3]
   [4] [5]       [6]  [7]

   With dense: small items backfill the gaps
   [1] [wide-2 ] [3] [4]
   [5] [6]       [7]  [8] */

.dynamic-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  /* Explicit rows */
  grid-template-rows: 200px 200px;
  /* Implicit rows (items beyond row 2) */
  grid-auto-rows: minmax(150px, auto);
  gap: 16px;
}

/* Column flow with implicit columns */
.timeline {
  display: grid;
  grid-template-rows: repeat(4, auto);
  grid-auto-flow: column;
  grid-auto-columns: 300px;
  gap: 20px;
  overflow-x: auto;
}

/* PAGE LAYOUT: Use Grid (two-dimensional) */
.page {
  display: grid;
  grid-template-columns: 250px 1fr;
  grid-template-rows: auto 1fr auto;
  grid-template-areas:
    "header header"
    "nav    main"
    "footer footer";
  min-height: 100vh;
}

/* NAVBAR: Use Flexbox (one-dimensional) */
.navbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 24px;
  height: 60px;
}

/* CARD GRID: Grid for the grid, Flex inside each card */
.card-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 24px;
}

.card {
  display: flex;
  flex-direction: column;
}

.card-body {
  flex: 1;
}

.card-footer {
  margin-top: auto;
}

